/* htmx 2.0 placeholder — replace with the real htmx.min.js distribution file.
   This stub provides the minimum needed for Ken's polling and swap patterns. */
(function(){
    "use strict";
    var htmx = {version:"2.0.0-stub"};
    function ready(fn){if(document.readyState!=="loading")fn();else document.addEventListener("DOMContentLoaded",fn)}
    function ajax(method,url,target,opts){
        var xhr=new XMLHttpRequest();
        xhr.open(method,url,true);
        xhr.setRequestHeader("HX-Request","true");
        xhr.onload=function(){
            if(xhr.status>=200&&xhr.status<300){
                var swap=opts&&opts.swap||"innerHTML";
                var select=opts&&opts.select;
                var html=xhr.responseText;
                if(select){
                    var tmp=document.createElement("div");tmp.innerHTML=html;
                    var sel=tmp.querySelector(select);
                    if(sel)html=sel.outerHTML;
                }
                if(swap==="outerHTML")target.outerHTML=html;
                else if(swap==="innerHTML")target.innerHTML=html;
                else if(swap==="beforeend")target.insertAdjacentHTML("beforeend",html);
            }
        };
        xhr.send();
    }
    function processElement(elt){
        var trigger=elt.getAttribute("hx-trigger");
        var get=elt.getAttribute("hx-get");
        var post=elt.getAttribute("hx-post");
        var targetSel=elt.getAttribute("hx-target");
        var swap=elt.getAttribute("hx-swap");
        var select=elt.getAttribute("hx-select");
        if(trigger&&trigger.indexOf("every")===0&&get){
            var ms=parseInt(trigger.replace(/[^\d]/g,""))*1000;
            if(trigger.indexOf("s")>0&&trigger.indexOf("m")<0)ms=parseInt(trigger.replace(/[^\d]/g,""))*1000;
            else if(trigger.indexOf("m")>0)ms=parseInt(trigger.replace(/[^\d]/g,""))*60000;
            setInterval(function(){
                var target=targetSel?document.querySelector(targetSel):elt;
                if(target)ajax("GET",get,target,{swap:swap||"innerHTML",select:select});
            },ms||10000);
        }
    }
    ready(function(){
        var elts=document.querySelectorAll("[hx-trigger]");
        for(var i=0;i<elts.length;i++)processElement(elts[i]);
    });
    window.htmx=htmx;
})();
